script.code:
def affil = primaryAffiliation != null ? basic.stringify(primaryAffiliation).trim().toLowerCase() : '';
if (affil != 'student') return null; // weak: no sobrescribe — solo side-effect
def sc = focus != null ? basic.getExtensionPropertyValue(focus, new javax.xml.namespace.QName('urn:sciback:midpoint:person', 'studentCycle')) : null
if (sc != null && (academicProgramCode == null || (academicProgramCode instanceof java.util.Collection ? academicProgramCode.isEmpty() : academicProgramCode.toString().isEmpty()))) {
    log.warn("UPeU Student: cycle={} sin academicProgramCode en user {}", sc, focus?.name)
}
return null // weak: no sobrescribe studentCycle — solo side-effect de log

// Resolución P-code -> INEI 8 díg via LookupTable LT-Pcode-INEI.
// Mismo idiom que Q5 (getObject(LookupTableType) + F_ROW retrieve);
// MidpointFunctions NO expone getLookupTableEntry() en 4.10.2.
def pcode = academicProgramSuneduCode != null ? basic.stringify(academicProgramSuneduCode).trim() : '';
if (pcode == '') return null; // sin P-code (posgrado/2da-esp) → sin INEI → Koha sin Bsort2
def inei = null;
try {
    def tableOid = 'e129d9e4-c2fd-4a02-9369-0ae5b8f59c06';
    def ltClass = com.evolveum.midpoint.xml.ns._public.common.common_3.LookupTableType.class;
    def options = com.evolveum.midpoint.schema.SelectorOptions.createCollection(
        prismContext.toUniformPath(com.evolveum.midpoint.xml.ns._public.common.common_3.LookupTableType.F_ROW),
        com.evolveum.midpoint.schema.GetOperationOptions.createRetrieve()
    );
    def tableObj = midpoint.getObject(ltClass, tableOid, options);
    def rows = tableObj != null ? tableObj.getRow() : null;
    if (rows != null) {
        for (def row : rows) {
            if (row.getKey() != null && row.getKey().trim() == pcode) {
                inei = row.getValue() != null ? row.getValue().trim() : null;
                break;
            }
        }
    }
} catch (Exception e) {
    log.warn("UPeU INEI: error leyendo LookupTable LT-Pcode-INEI para P-code '{}' en {}: {} — INEI vacío.", pcode, focus?.name, e.getMessage());
    return null;
}
if (inei == null) {
    log.warn("UPeU INEI: P-code '{}' sin entrada en LT-Pcode-INEI para {} — INEI vacío (Koha sin Bsort2). Agregar la fila si el programa debe migrarse.", pcode, focus?.name);
    return null;
}
return inei

// D-autoassign-ar-koha-patron-alumni: calcula validTo = 31-Dic(graduationYear+2)
// graduationYear llega como Integer (xsd:int) desde Oracle LAMB.
// Retornamos String ISO-8601: MidPoint convierte String→XMLGregorianCalendar
// al asignar al target activation/validTo, evitando ClassCastException en
// combinatorial evaluation (MidPoint 4.10.x bug con DatatypeFactory en populate).
def gy = graduationYear;
if (gy instanceof java.util.Collection) {
    gy = gy.isEmpty() ? null : gy.iterator().next();
}
if (gy == null) return null;  // fail-open: vigencia indefinida
def yearInt;
try {
    yearInt = (gy instanceof Number) ? ((Number) gy).intValue() : Integer.parseInt(gy.toString().trim());
} catch (Exception ignore) {
    log.warn('D-autoassign-ar-koha-patron-alumni: graduationYear no parseable: {}', gy);
    return null;
}
// Retornar como String — MidPoint parsea xsd:dateTime desde String sin ClassCastException
return String.format('%04d-12-31T23:59:59-05:00', yearInt + 2);

def aff = primaryAffiliation != null ? basic.stringify(primaryAffiliation).trim().toLowerCase() : '';
def QN = new javax.xml.namespace.QName('urn:sciback:midpoint:person','liveAffiliationWorker')
def liveWorker = basic.getExtensionPropertyValue(focus, QN)
aff == 'staff' || aff == 'faculty' || (liveWorker != null && (aff == 'alum' || aff == 'student'))

if (input == null || (basic.stringify(input).trim() in ['Estudiante','Egresado'])) return false
def QN = new javax.xml.namespace.QName('urn:sciback:midpoint:person','liveAffiliationWorker')
def relP = null
try { relP = focus?.asPrismObject()?.findProperty(com.evolveum.midpoint.prism.path.ItemPath.create('extension', QN))?.realValue } catch (Exception e) {}
def perP = null
try {
  if (focus?.oid != null) {
    def repoUser = midpoint.getObjectByOid(com.evolveum.midpoint.xml.ns._public.common.common_3.UserType.class, focus.oid)
    perP = repoUser?.asPrismObject()?.findProperty(com.evolveum.midpoint.prism.path.ItemPath.create('extension', QN))?.realValue
  }
} catch (Exception e) {}
return (relP == null && perP == null)

if (input == null || !basic.stringify(input).trim().matches('\\d+')) return false
def QN = new javax.xml.namespace.QName('urn:sciback:midpoint:person','liveAffiliationWorker')
def relP = null
try { relP = focus?.asPrismObject()?.findProperty(com.evolveum.midpoint.prism.path.ItemPath.create('extension', QN))?.realValue } catch (Exception e) {}
def perP = null
try {
  if (focus?.oid != null) {
    def repoUser = midpoint.getObjectByOid(com.evolveum.midpoint.xml.ns._public.common.common_3.UserType.class, focus.oid)
    perP = repoUser?.asPrismObject()?.findProperty(com.evolveum.midpoint.prism.path.ItemPath.create('extension', QN))?.realValue
  }
} catch (Exception e) {}
return (relP == null && perP == null)

if (input == null || basic.stringify(input).trim().toLowerCase().endsWith('@upeu.edu.pe')) return false
def QN = new javax.xml.namespace.QName('urn:sciback:midpoint:person','liveAffiliationWorker')
def relP = null
try { relP = focus?.asPrismObject()?.findProperty(com.evolveum.midpoint.prism.path.ItemPath.create('extension', QN))?.realValue } catch (Exception e) {}
def perP = null
try {
  if (focus?.oid != null) {
    def repoUser = midpoint.getObjectByOid(com.evolveum.midpoint.xml.ns._public.common.common_3.UserType.class, focus.oid)
    perP = repoUser?.asPrismObject()?.findProperty(com.evolveum.midpoint.prism.path.ItemPath.create('extension', QN))?.realValue
  }
} catch (Exception e) {}
return (relP == null && perP == null)

// BLOQUE L — state machine canónica de lifecycleState (2026-05-29; rama archived H3 2026-05-30).
// Señal de afiliación VIVA = affiliations (multi-valor, post-inbound). NO lee lifecycleState
// (sin dependencia circular). NO usa grace periods en el template: la temporalidad post-cese
// vive en la IIA (searchScript del worker mantiene el token durante el período de gracia).
def CANONICAL = ['faculty','staff','student','alum','affiliate'] as Set;
// FIX OPCIÓN 2: liveAff = unión de los items persistidos por IIA (single-source, materializados).
def liveAff = [worker, student, alum].collect { it != null ? basic.stringify(it).trim().toLowerCase() : '' }
    .findAll { it in CANONICAL } as Set;
def termStr = terminationDate != null ? basic.stringify(terminationDate).trim() : '';

// (1) Tiene >= 1 afiliación viva → nunca archivar (§1.2 archived != destroyed).
if (!liveAff.isEmpty()) {
    def pn = personalNumber != null ? basic.stringify(personalNumber).trim() : '';
    def hasPersonalNumber = (pn != '');
    def hasPrimaryDoc = false;
    try {
        def primPath = com.evolveum.midpoint.prism.path.ItemPath.create(new javax.xml.namespace.QName('urn:sciback:midpoint:person', 'primary'));
        def docs = identityDocuments;
        if (docs != null) {
            def docList = (docs instanceof List) ? docs : [docs];
            hasPrimaryDoc = docList.any { doc -> def p = doc?.findProperty(primPath); p != null && 'true' == p?.realValue?.toString() }
        }
    } catch (Exception e) { log.warn('Bloque L: error leyendo identityDocuments en {}: {}', focus?.name, e.message) }
    if (!hasPrimaryDoc && taxId != null) {
        def txStr = basic.stringify(taxId)?.trim();
        if (txStr?.startsWith('urn:schac:personalUniqueID:')) hasPrimaryDoc = true
    }
    if (hasPersonalNumber && hasPrimaryDoc) { return 'active' }
    log.info('Bloque L: {} con afiliacion viva {} pero perfil incompleto (pn={}, doc={}) -> draft', focus?.name, liveAff, hasPersonalNumber, hasPrimaryDoc);
    return 'draft'
}

// === Sin afiliación viva ===
// Detectar EVIDENCIA LABORAL PREVIA: structural archetype employee-staff/faculty asignado
// (señal persistente de que la persona tuvo/tiene vínculo laboral, aunque LAMB no traiga
//  terminationDate — caso típico de denominacional fuera de scope o ex-empleado sin fecha de cese).
// OIDs structural employee: staff=6460facf-3abf-4851-966e-0c95aa1a6c46 ; faculty=c93083ca-f4c5-4704-acf4-d53b97c9556e
def EMPLOYEE_STRUCT = ['6460facf-3abf-4851-966e-0c95aa1a6c46','c93083ca-f4c5-4704-acf4-d53b97c9556e'] as Set;
def hasEmploymentEvidence = false;
try {
    // leer desde la variable `focus` (NO un source declarado) => mapping se evalua UNA vez
    hasEmploymentEvidence = focus?.assignment?.any { a ->
        def tr = a?.targetRef;
        tr != null && (tr.oid in EMPLOYEE_STRUCT)
    } ?: false
} catch (Exception e) { log.warn('Bloque L: error leyendo focus.assignment en {}: {}', focus?.name, e.message) }

// (2) Sin afiliación viva, pero tuvo empleo (terminationDate) → leaver real → archived.
if (termStr != '') {
    log.info('Bloque L: {} sin afiliacion viva + con terminationDate {} -> archived (leaver)', focus?.name, termStr);
    return 'archived'
}

// (H3, 2026-05-30) Sin afiliación viva, sin terminationDate, PERO con structural employee/faculty
// (evidencia laboral previa) → ex-empleado denominacional/fuera-de-scope → archived.
// §1.2 ISO 24760: tuvo identidad laboral establecida; al perder toda afiliación viva pasa a archived,
// NO a draft (draft = alta nunca-activada). Salvaguarda académica intacta: egresados/estudiantes
// tienen liveAffiliationAlum/Student y caen en (1), nunca llegan aquí.
if (hasEmploymentEvidence) {
    log.info('Bloque L: {} sin afiliacion viva + sin terminationDate + structural employee/faculty (evidencia laboral) -> archived (H3)', focus?.name);
    return 'archived'
}

// (3) Sin afiliación viva, sin historia laboral, sin evidencia de empleo → perfil genuinamente
// incompleto/nunca-activo → draft (no archivar).
log.info('Bloque L: {} sin afiliacion viva, sin terminationDate, sin evidencia laboral -> draft (alta incompleta)', focus?.name);
return 'draft'

import java.time.LocalDate; import com.evolveum.midpoint.xml.ns._public.common.common_3.ActivationStatusType;
def aff = primaryAffiliation != null ? basic.stringify(primaryAffiliation).trim().toLowerCase() : '';
// Este mapping (strong) GOBIERNA administrativeStatus para usuarios con terminationDate.
// Retorna ENABLED (no null) cuando NO corresponde desactivar, para sobrescribir cualquier
// DISABLED huérfano dejado por reactions previos (inactivateFocus). Caso clave: ex-trabajador
// que ahora es alumni/student → debe quedar ENABLED aunque tenga terminationDate.
if (terminationDate == null) return null;
def v = basic.stringify(terminationDate);
if (!(v ==~ /^\d{4}-\d{2}-\d{2}$/)) return ActivationStatusType.ENABLED;
// Solo desactivar a trabajador VIGENTE (staff/faculty) con fecha de cese ya cumplida.
if (['staff','faculty'].contains(aff)) {
    try { def td = LocalDate.parse(v); if (!td.isAfter(LocalDate.now())) { return ActivationStatusType.DISABLED } } catch (Exception e) { log.warn("UPeU template leaver: terminationDate no parseable '{}' en {}: {}", v, focus?.name, e.message); return ActivationStatusType.ENABLED }
    return ActivationStatusType.ENABLED
}
// Afiliación no laboral (alum/student/affiliate/null) con terminationDate: recuperar ENABLED.
return ActivationStatusType.ENABLED

// FIX 2026-05-31 (G1): costCenter = ID_AREA numérico puro (no 'area.NN').
// ID_AREA 93 = CRAI institucional (ELISEO.ORG_AREA, validado vs Oracle).
def cc = costCenter != null ? basic.stringify(costCenter).trim() : '';
['93'].contains(cc)

// Resolución ID_PUESTO -> tier via LookupTable LT-CRAI-Puesto-Tier.
// API verificada en MidPoint 4.10.2 (2026-05-22): la interfaz MidpointFunctions
// NO expone getLookupTableEntry(). Lectura robusta = getObject(LookupTableType)
// recuperando el contenedor incremental F_ROW con GetOperationOptions.createRetrieve()
// e iterando las filas. Mismo patrón canónico ya productivo en la
// FunctionLibrary sb-program-resolver (OID 6a99f9de-5db6-43d5-9b20-0cfd2b79ecf9).
def pid = lambPositionId != null ? basic.stringify(lambPositionId).trim() : '';
def tierMap = [
    'direccion'         : 'AR-Koha-Librarian-Direccion',
    'supervision'       : 'AR-Koha-Librarian-Supervision',
    'procesos-tecnicos' : 'AR-Koha-Librarian-ProcesosTecnicos',
    'circulacion'       : 'AR-Koha-Librarian-Circulacion',
    'soporte'           : 'AR-Koha-Librarian-Soporte'
];
def tier = null;
if (pid != '') {
    try {
        def tableOid = 'ebe291d2-6375-49f8-aa6f-5afeee959f4e';
        def ltClass = com.evolveum.midpoint.xml.ns._public.common.common_3.LookupTableType.class;
        def options = com.evolveum.midpoint.schema.SelectorOptions.createCollection(
            prismContext.toUniformPath(com.evolveum.midpoint.xml.ns._public.common.common_3.LookupTableType.F_ROW),
            com.evolveum.midpoint.schema.GetOperationOptions.createRetrieve()
        );
        def tableObj = midpoint.getObject(ltClass, tableOid, options);
        def rows = tableObj != null ? tableObj.getRow() : null;
        if (rows != null) {
            for (def row : rows) {
                if (row.getKey() != null && row.getKey().trim() == pid) {
                    tier = row.getValue() != null ? row.getValue().trim() : null;
                    break;
                }
            }
        }
    } catch (Exception e) {
        log.warn("UPeU CRAI tier: error leyendo LookupTable LT-CRAI-Puesto-Tier para ID_PUESTO '{}': {} — fallback a tier mínimo.", pid, e.getMessage());
    }
}
def roleName = tierMap[tier];
if (roleName == null) {
    log.warn("UPeU CRAI tier: ID_PUESTO '{}' desconocido o ausente para {} — fallback a tier mínimo (circulacion). Agregar la fila a LT-CRAI-Puesto-Tier.", pid, focus?.name);
    roleName = 'AR-Koha-Librarian-Circulacion';
}
return roleName

// FIX 2026-05-31 (G1): costCenter = ID_AREA numérico puro (no 'area.NN').
// ID_AREA 93 = CRAI institucional (ELISEO.ORG_AREA, validado vs Oracle).
def cc = costCenter != null ? basic.stringify(costCenter).trim() : '';
['93'].contains(cc)

def CANONICAL = ['faculty','staff','student','alum','affiliate'] as Set;
def live = [] as Set;
[worker, student, alum].each { def v = it != null ? basic.stringify(it).trim().toLowerCase() : ''; if (v in CANONICAL) live << v };
return new ArrayList(live)

def CANONICAL = ['faculty','staff','student','alum','affiliate'];
def live = [] as Set;
[worker, student, alum].each { def v = it != null ? basic.stringify(it).trim().toLowerCase() : ''; if (v in CANONICAL) live << v };
if (live.isEmpty()) { log.debug('J3: sin afiliación viva en {} — primaryAffiliation null', focus?.name); return null };
for (def canon : CANONICAL) {
    if (canon in live) { log.debug('J3: primaryAffiliation={} (de liveAff={}) en {}', canon, live, focus?.name); return canon }
};
return null

def mc = motivoCese != null ? basic.stringify(motivoCese).trim().toLowerCase() : '';
if (mc != 'jubilacion') return null; // no aplica — J3 calcula normalmente

// Decisión B: si hay afiliación viva de mayor prioridad que alum, J3 gana
// FIX OPCIÓN 2 (2026-05-30): lee items persistidos por IIA, no el transitorio affiliations.
def affs = [worker, student, alum].collect { it != null ? basic.stringify(it).trim().toLowerCase() : '' }
    .findAll { it in ['faculty','staff','student','alum','affiliate'] } as Set;
def HIGHER_THAN_ALUM = ['faculty','staff','student'] as Set;
if (affs.any { it in HIGHER_THAN_ALUM }) {
    log.debug('K-jubilado: afiliación de mayor prioridad encontrada {} — J3 calcula para {}', affs, focus?.name);
    return null; // J3 ganará
}

// Jubilado puro o jubilado + affiliate → forzar alum
log.info('K-jubilado: motivoCese=jubilacion, sin afiliación mayor → alum para {}', focus?.name);
return 'alum'

def mc = motivoCese != null ? basic.stringify(motivoCese).trim().toLowerCase() : '';
if (mc != 'jubilacion') return null;

def affs = (affiliations ?: []).collect { basic.stringify(it).trim().toLowerCase() }
    .findAll { it in ['faculty','staff','student','alum','affiliate'] } as Set;
def HIGHER_THAN_ALUM = ['faculty','staff','student'] as Set;
if (affs.any { it in HIGHER_THAN_ALUM }) return null; // K no se activó, no tocar formerRole

// Buscar el valor staff o faculty que el jubilado tenía antes
def WORKER_AFFS = ['faculty','staff'] as Set;
def former = affs.find { it in WORKER_AFFS };
if (former) { log.debug('K2: formerRole={} para jubilado {}', former, focus?.name); return former };
return null
